import{_ as e,o as i,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Team Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/team.md","filePath":"analytics/team.md"}'),n={name:"analytics/team.md"};function r(s,a,o,d,c,h){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="team-analytics" tabindex="-1">Team Analytics <a class="header-anchor" href="#team-analytics" aria-label="Permalink to &quot;Team Analytics&quot;">​</a></h1><p>Team analytics aggregate individual player data to give coaches a view of overall team performance and identify systemic development areas.</p><h2 id="accessing-team-analytics" tabindex="-1">Accessing Team Analytics <a class="header-anchor" href="#accessing-team-analytics" aria-label="Permalink to &quot;Accessing Team Analytics&quot;">​</a></h2><p>From the Analytics screen tap <strong>Team</strong> at the top to switch from individual to team view.</p><h2 id="team-pitching" tabindex="-1">Team Pitching <a class="header-anchor" href="#team-pitching" aria-label="Permalink to &quot;Team Pitching&quot;">​</a></h2><ul><li>Combined team ERA across all pitchers</li><li>Leaderboard sorted by ERA (minimum innings threshold applied)</li><li>Strike rate across all pitchers</li><li>Team strikeout-to-walk ratio</li></ul><h2 id="team-hitting" tabindex="-1">Team Hitting <a class="header-anchor" href="#team-hitting" aria-label="Permalink to &quot;Team Hitting&quot;">​</a></h2><ul><li>Team batting average and OBP</li><li>Combined spray chart showing all batted balls</li><li>Leaderboard sorted by batting average (minimum at-bat threshold applied)</li><li>Team hard hit rate</li><li>Team strikeout rate and walk rate</li></ul><h2 id="team-fielding" tabindex="-1">Team Fielding <a class="header-anchor" href="#team-fielding" aria-label="Permalink to &quot;Team Fielding&quot;">​</a></h2><ul><li>Team fielding percentage</li><li>Leaderboard sorted by FLD% (minimum chances threshold applied)</li><li>Error breakdown by position — identifies which positions are generating the most errors</li></ul><h2 id="team-baserunning" tabindex="-1">Team Baserunning <a class="header-anchor" href="#team-baserunning" aria-label="Permalink to &quot;Team Baserunning&quot;">​</a></h2><ul><li>Team stolen base percentage</li><li>Leaderboard sorted by SB%</li><li>Total steals and caught stealing counts</li></ul><h2 id="leaderboard-thresholds" tabindex="-1">Leaderboard Thresholds <a class="header-anchor" href="#leaderboard-thresholds" aria-label="Permalink to &quot;Leaderboard Thresholds&quot;">​</a></h2><p>Minimum sample sizes are required to appear on leaderboards:</p><ul><li>Pitching: 5+ innings pitched</li><li>Hitting: 10+ at-bats</li><li>Fielding: 10+ fielding chances</li><li>Baserunning: 5+ attempts</li></ul><p>Players below threshold show in a separate section labeled &quot;Insufficient data.&quot;</p><h2 id="organization-plan-—-cross-team-analytics" tabindex="-1">Organization Plan — Cross-Team Analytics <a class="header-anchor" href="#organization-plan-—-cross-team-analytics" aria-label="Permalink to &quot;Organization Plan — Cross-Team Analytics&quot;">​</a></h2><p>Organization plan subscribers can view aggregate analytics across all teams in their organization. This is useful for club directors evaluating player development across multiple age groups or coaches.</p>',18)])])}const u=e(n,[["render",r]]);export{g as __pageData,u as default};
